                    public static void ScriptMain(Project project)
                    {
                        string versionFileToUpdate = project.Properties["VersionFileToUpdate"];
                        AutoIncrementAPI autoIncrement = new AutoIncrementAPI(project.Properties["VersionInfoFile"]);

                        project.Log(Level.Info, string.Format("Updating version in {0} to {1}", versionFileToUpdate, autoIncrement.NextVersion));

                        if( !autoIncrement.UpdateVersion(versionFileToUpdate))
                        {
                            project.Log(Level.Error, string.Format( "Failed to change version in {0} - {1}", versionFileToUpdate, autoIncrement.ErrorMessage));
                        }
                    }

            
    			    public static void ScriptMain(Project project)
              {
                string fileName = (string)project.Properties["testResultFile"];
                DirectoryInfo di = new DirectoryInfo( (String)project.Properties["projectName" ] );
                XmlDocument testResults = new XmlDocument();
                testResults.Load( fileName );

                int count = testResults.SelectNodes( "//test-case" ).Count;
                int fail = testResults.SelectNodes( "//test-case[@success='False' or @executed='False']" ).Count;
                Double percent = (1.0 - (Convert.ToDouble(fail) / count));
                project.Properties[ "propertyName" ] = string.Format( (string)project.Properties["test.result.key"]+".{0}", di.Name );
                project.Properties[ "propertyValue" ] = percent.ToString("00.0#%") + " (" + (count-fail) + "/" + count + ")";
            }

            
    			    public static void ScriptMain(Project project)
              {
                string fileName = (String)project.Properties["testResultFile"];
                DirectoryInfo di = new DirectoryInfo( (String)project.Properties["projectName" ] );
                XmlDocument testResults = new XmlDocument();
                testResults.Load( fileName );

                XmlNodeList nodeList = testResults.SelectNodes( "//testsuite" );

                int bad = 0;
          	    int total = 0;

                foreach( XmlNode node in nodeList )
                {
                  XmlAttributeCollection attribs = node.Attributes;

                  string count = attribs["tests"].Value;
                  string fail  = attribs["failures"].Value;
                  string error = attribs["errors"].Value;

                  bad += Int32.Parse(fail) + Int32.Parse(error);
                  total += Int32.Parse(count);
                }
                Double percent = (1.0 - (Convert.ToDouble(bad)/total));

                project.Properties[ "propertyName" ] = "roi.server.test";
                project.Properties[ "propertyValue" ] = percent.ToString("00.0#%") + " (" + (total-bad) + "/" + total + ")";
            }

            
    			    public static void ScriptMain(Project project)
              {
                string fileName = (String)project.Properties["coverageFile"];
                DirectoryInfo di = new DirectoryInfo( (String)project.Properties["projectName" ] );
                XmlDocument testResults = new XmlDocument();
                testResults.Load( fileName );

                XmlNodeList modules = testResults.SelectNodes( string.Format( "//module[@name='{0}.DLL']", di.Name ) );
                int total = 0;
                int unvisited = 0;

                foreach( XmlNode module in modules )
                {
                  total += Int32.Parse( module.Attributes[ "sequencePoints" ].Value );
                  unvisited += Int32.Parse( module.Attributes[ "unvisitedPoints" ].Value );
                }

                float percent = 0.0f;

                if( total > 0 )
                {
                  percent = (((float)total - (float)unvisited)/(float)total);
                }

                project.Properties[ "propertyName" ] = string.Format( "roi.client.coverage.{0}", di.Name );
                project.Properties[ "propertyValue" ] = string.Format( "{0} ({1}/{2})",
                  percent.ToString( "00.0#%" ), total - unvisited, total );
            }

            
    			    public static void ScriptMain(Project project)
              {
                string fileName = (String)project.Properties["coverageFile"];
                DirectoryInfo di = new DirectoryInfo( (String)project.Properties["projectName" ] );
                XmlDocument testResults = new XmlDocument();
                testResults.Load( fileName );

                XmlNodeList Assemblies = testResults.SelectNodes("//Assembly");
                int total = 0;
                int unvisited = 0;

                foreach( XmlNode Assembly in Assemblies )
				{
				  System.Console.WriteLine( Assembly.Attributes[ "name" ].Value );
				  if( Assembly.Attributes[ "name" ].Value.StartsWith( di.Name ) )
				  {
					total += Int32.Parse( Assembly.Attributes[ "coverablelines" ].Value );
					unvisited += Int32.Parse( Assembly.Attributes[ "coverablelines" ].Value ) - Int32.Parse( Assembly.Attributes[ "coveredlines" ].Value );
				  }
				}
			
                float percent = 0.0f;

                if( total > 0 )
                {
                  percent = (((float)total - (float)unvisited)/(float)total);
                }

                project.Properties[ "propertyName" ] = string.Format( "roi.client.coverage.{0}", di.Name );
                project.Properties[ "propertyValue" ] = string.Format( "{0} ({1}/{2})",
                  percent.ToString( "00.0#%" ), total - unvisited, total );
            }

            
    			    public static void ScriptMain(Project project)
              {
                DirectoryInfo di = new DirectoryInfo( (String)project.Properties["projectName" ] );
                //string fileName = string.Format( "{0}\\{1}Test.xml", di.FullName, di.Name );
                string fileName = (String)project.Properties["coverageFile"];
                if( !File.Exists( fileName ) )
                {
                  return;
                }

                XmlDocument testResults = new XmlDocument();
                testResults.Load( fileName );

                XmlNode allNode = testResults.SelectSingleNode( "//all" );
                XmlNodeList coverageNodes = allNode.SelectNodes( "./coverage" );

                foreach( XmlNode node in coverageNodes )
                {
                  if( node.Attributes[ "type" ].Value != "line, %" )
                  {
                    continue;
                  }

                  project.Properties[ "propertyValue" ] = node.Attributes[ "value" ].Value;
                  break;
                }

                project.Properties[ "propertyName" ] = "roi.server.coverage";
            }

            
