                    public static void ScriptMain(Project project)
              {
                string currentResultFileName = (String)project.Properties["currentResultFileName"];
                string previousResultFileName = (String)project.Properties["previousResultFileName"];
          	    string comparedResultFileName = (String)project.Properties["comparedResultFileName"];

                XmlDocument currentBuildResults = new XmlDocument();
                XmlDocument previousBuildResults = new XmlDocument();
                currentBuildResults.Load( currentResultFileName );

                XmlNodeList allNodes = currentBuildResults.SelectNodes( "//property" );

                string previousVal = null;
                string result = null;
                string result1 = null;
                string name = null;
                string value = null;

                FileStream fs = new FileStream(comparedResultFileName, FileMode.Create, FileAccess.ReadWrite);
                StreamWriter sw = new StreamWriter(fs);
                if (!File.Exists(previousResultFileName)) {

                     foreach(XmlNode node in allNodes)
                     {
                         name = node.Attributes["name"].Value;
                         result = "<font class=\"equal-symbol\" >&#9658;</font>";

                         sw.WriteLine("compared." + name + "=" + result);
          	             sw.WriteLine("compared." + name + ".min=" + "class=\"increased-font\" >");
                         sw.WriteLine("previous." + name + "=-N.A-");
                     }
                     sw.WriteLine("previous.successfull.build.version=-N.A-");
          	         sw.WriteLine("previous.successfull.build.reports.dir=#");

               } else {
                   previousBuildResults.Load( previousResultFileName );
                   XmlElement previousRoot = previousBuildResults.DocumentElement;
              	   foreach( XmlNode node in allNodes )
                    {
                        name = node.Attributes["name"].Value;
                        value = node.Attributes["value"].Value ;
                        if (value.IndexOf("%") != -1) value = value.Substring(0, value.IndexOf("%"));
                        previousVal = ((XmlElement)previousRoot.SelectSingleNode("/properties/property[@name='"+"previous."+name+"']")).GetAttribute("value");
                        if (previousVal.IndexOf("%") != -1) previousVal =  previousVal.Substring(0, previousVal.IndexOf("%"));
                        bool isCodeStd =  (name.IndexOf("code") != -1);
                        bool isCoverage =  (name.IndexOf("coverage") != -1);
              	        bool isTestCase =  (name.IndexOf("test") != -1);

              	        if ((isTestCase && Double.Parse(value) < Double.Parse((String)project.Properties["report.min.test.percentage"]))
                            ||(isCoverage && Double.Parse(value) < Double.Parse((String)project.Properties["report.min.coverage.percentage"]))
              	            ||(isCodeStd && Double.Parse(value) > Double.Parse((String)project.Properties["report.min.codestd.errors"]))) {
              	            result1 = "class=\"decreased-font\" >";
                        } else {
              	            result1 = "class=\"increased-font\" >";
              	        }

                        if(Double.Parse(value) > Double.Parse(previousVal)) {
                            result = "<font class=\"increased-symbol\" >&#9650;</font>";
                            if (isCodeStd) {
                                result = "<font class=\"decreased-symbol\" >&#9660;</font>";
                            }
                        } else if(Double.Parse(value) < Double.Parse(previousVal)) {
                            result = "<font class=\"decreased-symbol\" >&#9660;</font>";
                            if (isCodeStd) {
                                result = "<font class=\"increased-symbol\" >&#9650;</font>";
                            }
                        } else {
                            result = "<font class=\"equal-symbol\" >&#9658;</font>";
                            if(Double.Parse(value) == 100) {
                               result = "<font class=\"equal-symbol\" >&#9733;</font>";
                            }
                            if (isCodeStd && Double.Parse(value) == 0) {
                              result = "<font class=\"equal-symbol\" >&#9733;</font>";
                            }
                        }

                       sw.WriteLine("compared." + name + "=" + result);
                       sw.WriteLine("compared." + name + ".min=" + result1);

                    }
                }
                sw.Close();
                fs.Close();
             }

            
              public static void ScriptMain(Project project)
              {
                string roiMetricsProperties = (String)project.Properties["roiMetricsProperties"];
                string clientPerfReports = (String)project.Properties["clientPerfReports"];
          	    string serverPerfReports = (String)project.Properties["serverPerfReports"];
          	    string clientMetricsLog = (String)project.Properties["clientMetricsLog"];
          	    string type = (String)project.Properties["perfReportType"];
          	    Boolean isClient = type.Equals("Client") ? true : false;
                string fileName = isClient ? clientMetricsLog : roiMetricsProperties;
                if(!File.Exists(fileName))
                {
                  return;
                }
          	    string performanceReports = isClient ? clientPerfReports : serverPerfReports;

                FileStream fs = new FileStream(fileName, FileMode.Open, FileAccess.Read);
                StreamReader sr = new StreamReader(fs);

                Dictionary<string, object> packageDictionary = new Dictionary<string, object>();
                Dictionary<string, double> methodCountDictionary = new Dictionary<string, double>();
                Dictionary<string, double> methodMinTimeDictionary = new Dictionary<string, double>();
                Dictionary<string, double> methodMaxTimeDictionary = new Dictionary<string, double>();
                Dictionary<string, double> preServiceTimeDictionary = new Dictionary<string, double>();
                int splitLength = isClient ? 9 : 4;
                string title = isClient ? "Namespaces" : "Packages";
          	    string timeUnit = "ms";
                string line;
                while ((line = sr.ReadLine()) != null)
                {
                    if (line.IndexOf('|') != -1)
                    {
                        string[] splits = line.Split('|');
                        if (splits.Length == splitLength)
                        {
                            string txnId = isClient ? splits[4].Trim() : splits[0].Trim();
                            string serviceType = splits[1].Trim();
                            string key = splits[2].Trim();
                            double timeTaken = isClient ? (Double.Parse(splits[6].Trim()) * 1000) : Double.Parse(splits[3].Trim());

          	                if (isClient && !serviceType.Equals("Service"))
          	                {
          	                    continue;
          	                }
                            if (!isClient && !serviceType.Equals("Web Service Invocation"))
                            {
                                if (preServiceTimeDictionary.ContainsKey(txnId))
                                {
                                    preServiceTimeDictionary[txnId] += timeTaken;
                                }
                                else
                                {
                                    preServiceTimeDictionary.Add(txnId, timeTaken);
                                }
                                continue;
                            }
                            key = (!isClient) ? key.Substring(0, key.LastIndexOf('(')) : key;
                            string methodName = key.Substring(key.LastIndexOf('.') + 1);
                            string qClassName = key.Substring(0, key.LastIndexOf('.'));
                            string packageName = qClassName.Substring(0, qClassName.LastIndexOf('.'));
                            string className = qClassName.Substring(qClassName.LastIndexOf('.') + 1);
                            if (isClient && className.Equals("TestROIHelper"))
                            {
                                continue;
                            }

                            if (preServiceTimeDictionary.ContainsKey(txnId))
                            {
                                timeTaken += preServiceTimeDictionary[txnId];
                            }

                            if (methodCountDictionary.ContainsKey(key))
                            {
                                methodCountDictionary[key] += 1;
                            }
                            else
                            {
                                methodCountDictionary.Add(key, 1);
                            }

                            if (methodMinTimeDictionary.ContainsKey(key))
                            {
                                methodMinTimeDictionary[key] = timeTaken < methodMinTimeDictionary[key] ? timeTaken : methodMinTimeDictionary[key];
                            }
                            else
                            {
                                methodMinTimeDictionary.Add(key, timeTaken);
                            }

                            if (methodMaxTimeDictionary.ContainsKey(key))
                            {
                                methodMaxTimeDictionary[key] = timeTaken > methodMaxTimeDictionary[key] ? timeTaken : methodMaxTimeDictionary[key];
                            }
                            else
                            {
                                methodMaxTimeDictionary.Add(key, timeTaken);
                            }

                            if (packageDictionary.ContainsKey(packageName))
                            {
                                Dictionary<string, object> classDictionary = (Dictionary<string, object>) packageDictionary[packageName];
                                if (classDictionary.ContainsKey(className))
                                {
                                    Dictionary<string, double> methodDictionary = (Dictionary<string, double>) classDictionary[className];
                                    if(methodDictionary.ContainsKey(methodName))
                                    {
                                        methodDictionary[methodName] += timeTaken;
                                        classDictionary[className] = methodDictionary;
                                        packageDictionary[packageName] = classDictionary;
                                    }
                                    else
                                    {
                                        methodDictionary.Add(methodName, timeTaken);
                                        classDictionary[className] = methodDictionary;
                                        packageDictionary[packageName] = classDictionary;
                                    }
                                }
                                else
                                {
                                    Dictionary<string, double> mthdDictionary = new Dictionary<string, double>();
                                    mthdDictionary.Add(methodName, timeTaken);
                                    classDictionary.Add(className, mthdDictionary);
                                    packageDictionary[packageName] = classDictionary;
                                }
                            }
                            else
                            {
                                Dictionary<string, object> classDictionary = new Dictionary<string, object>();
                                Dictionary<string, double> methodDictionary = new Dictionary<string, double>();
                                methodDictionary.Add(methodName, timeTaken);
                                classDictionary.Add(className, methodDictionary);
                                packageDictionary.Add(packageName, classDictionary);
                            }

                        }
                    }
                }
                sr.Close();
                fs.Close();

          	    string packagesHtml = performanceReports + @"\packages.html";
                FileStream fsw = new FileStream(packagesHtml, FileMode.Create, FileAccess.Write);
                StreamWriter sw = new StreamWriter(fsw);

          	    string classesHtml = performanceReports + @"\allClasses.html";
                FileStream fsw1 = new FileStream(classesHtml, FileMode.Create, FileAccess.Write);
                StreamWriter sw1 = new StreamWriter(fsw1);

                string summaryHtml = performanceReports + @"\summary.html";
                FileStream fsw4 = new FileStream(summaryHtml, FileMode.Create, FileAccess.Write);
                StreamWriter sw4 = new StreamWriter(fsw4);

                sw.WriteLine("<html> <head> <title>All " + title + "</title>");
                sw.WriteLine("<link rel=\"stylesheet\" type=\"text/css\" title=\"Style\" href=\"stylesheet.css\"> </head>");
                sw.WriteLine("<h2><a href=\"summary.html\" target=\"classFrame\">Home</a></h2>");
                sw.WriteLine("<body> <h2>" + title + "</h2>");
                sw.WriteLine("<table width=\"100%\">");

                sw1.WriteLine("<html> <head> <title>All Classes</title>");
                sw1.WriteLine("<link rel=\"stylesheet\" type=\"text/css\" title=\"Style\" href=\"stylesheet.css\"> </head>");
                sw1.WriteLine("<body> <h2>Classes</h2>");
                sw1.WriteLine("<table width=\"100%\">");

                sw4.WriteLine("<html> <head> <title>Perfomance Report</title>");
                sw4.WriteLine("<link rel=\"stylesheet\" type=\"text/css\" title=\"Style\" href=\"stylesheet.css\"> </head>");
                sw4.WriteLine("<body onload=\"open('allClasses.html','classListFrame')\">");
                sw4.WriteLine("<h1>ROI Performance Report</h1>");
                sw4.WriteLine("<hr size=\"1\">");
                sw4.WriteLine("<h2>Packages</h2>");
                sw4.WriteLine("<table class=\"details\" border=\"0\" cellpadding=\"5\" cellspacing=\"2\" width=\"95%\">");
                sw4.WriteLine("<tr valign=\"top\">");
                sw4.WriteLine("<th width=\"80%\">Name</th><th>Services</th> </tr>");

                IDictionaryEnumerator packageEnumerator = packageDictionary.GetEnumerator();
                while (packageEnumerator.MoveNext())
                {
                    string packageName = Convert.ToString(packageEnumerator.Key);
          	        int packageServices = 0;
                    sw.WriteLine("<tr>");
                    sw.WriteLine("<td nowrap=\"nowrap\"> <a href=\"" + packageName + "." + "classes.html" + "\" target=\"classListFrame\">" + packageName + "</a></td>");
                    sw.WriteLine("</tr>");
                    Dictionary<string, object> classDictionary = (Dictionary<string, object>)packageDictionary[packageName];

                    string packageClassesHtml = performanceReports + @"\" + packageName + "." + "classes.html";
                    FileStream fsw3 = new FileStream(packageClassesHtml, FileMode.Create, FileAccess.Write);
                    StreamWriter sw3 = new StreamWriter(fsw3);

                    sw3.WriteLine("<html> <head> <title>Classes</title>");
                    sw3.WriteLine("<link rel=\"stylesheet\" type=\"text/css\" title=\"Style\" href=\"stylesheet.css\"> </head>");
                    sw3.WriteLine("<body> <h3>" + packageName + "</h3>");
                    sw3.WriteLine("<h2>Classes</h2>");
                    sw3.WriteLine("<table width=\"100%\">");

                    IDictionaryEnumerator classEnumerator = classDictionary.GetEnumerator();
                    while (classEnumerator.MoveNext())
                    {
                        string className = Convert.ToString(classEnumerator.Key);
                        Dictionary<string, double> methodDictionary = (Dictionary<string, double>)classDictionary[className];

                        string classDetailsHtml = performanceReports + @"\" + packageName + "." + className + ".html";
                        FileStream fsw2 = new FileStream(classDetailsHtml, FileMode.Create, FileAccess.Write);
                        StreamWriter sw2 = new StreamWriter(fsw2);

                        sw3.WriteLine("<tr>");
                        sw3.WriteLine("<td nowrap=\"nowrap\"> <a href=\"" + packageName + "." + className + ".html" + "\" target=\"classFrame\">" + className + "</a></td>");
                        sw3.WriteLine("</tr>");

                        sw2.WriteLine("<html> <head> <title>Performance Metrics</title>");
                        sw2.WriteLine("<link rel=\"stylesheet\" type=\"text/css\" title=\"Style\" href=\"stylesheet.css\"> </head>");
                        sw2.WriteLine("<body> <h1>ROI Performance Metrics</h1>");
                        sw2.WriteLine("<hr size=\"1\">");
                        sw2.WriteLine("<h3>Class " + packageName + "." + className + "</h3>");

                        sw2.WriteLine("<table class=\"details\" border=\"0\" cellpadding=\"5\" cellspacing=\"2\" width=\"95%\">");
                        sw2.WriteLine("<tr valign=\"top\">");
                        sw2.WriteLine("<th width=\"80%\">Name</th><th>Services</th>");
                        sw2.WriteLine("</tr>");
                        sw2.WriteLine("<tr valign=\"top\" class=\"Pass\">");
                        sw2.WriteLine("<td>" + className + "</a></td><td>" + methodDictionary.Count + "</td>");
                        sw2.WriteLine("</tr></table>");

                        sw2.WriteLine("<h2>Services</h2>");
                        sw2.WriteLine("<table class=\"details\" border=\"0\" cellpadding=\"5\" cellspacing=\"2\" width=\"95%\">");
                        sw2.WriteLine("<tr valign=\"top\">");
                        sw2.WriteLine("<th>Name</th><th>Total Invocations</th><th>Total Time(" + timeUnit + ")</th><th>Min(" + timeUnit + ")</th><th>Avg(" + timeUnit + ")</th><th>Max(" + timeUnit + ")</th></tr>");

                        sw1.WriteLine("<tr>");
                        sw1.WriteLine("<td nowrap=\"nowrap\"> <a href=\"" + packageName + "." + className + ".html" + "\" target=\"classFrame\">" + className + "</a></td>");
                        sw1.WriteLine("</tr>");

                        IDictionaryEnumerator methodEnumerator = methodDictionary.GetEnumerator();
                        while (methodEnumerator.MoveNext())
                        {
                            string methodName = Convert.ToString(methodEnumerator.Key);
                            packageServices++;
                            double timeTaken = Double.Parse(Convert.ToString(methodEnumerator.Value));
                            double count = methodCountDictionary[packageName + "." + className + "." + methodName];
                            double min = methodMinTimeDictionary[packageName + "." + className + "." + methodName];
                            double max = methodMaxTimeDictionary[packageName + "." + className + "." + methodName];
                            double avgTime = timeTaken / count;
                            string avTime = avgTime.ToString("0.##");

                            sw2.WriteLine("<tr valign=\"top\" class=\"TableRowColor\">");
                            sw2.WriteLine("<td>" + methodName + "</td><td>" + count + "</td><td>" + timeTaken.ToString("0.##") + "</td><td>" + min.ToString("0.##") + "</td><td>" + avTime + "</td><td>" + max.ToString("0.##") + "</td>");
                            sw2.WriteLine("</tr>");
                        }
                        sw2.WriteLine("</table> </body> </html>");
                        sw2.Close();
                        fsw2.Close();
                    }

                    sw3.WriteLine("</table> </body> </html>");
                    sw3.Close();
                    fsw3.Close();

                    sw4.WriteLine("<tr valign=\"top\" class=\"Pass\">");
                    sw4.WriteLine("<td>" + packageName + "</td><td>" + packageServices + "</td>");
                    sw4.WriteLine("</tr>");
                }

                sw.WriteLine("</table> </body> </html>");
                sw1.WriteLine("</table> </body> </html>");

                sw.Close();
                fsw.Close();
                sw1.Close();
                fsw1.Close();
                sw4.Close();
                fsw4.Close();

              }

            
              public static void ScriptMain(Project project)
              {
                string type = (String)project.Properties["perfReportType"];
                Boolean isClient = type.Equals("Client") ? true : false;
                string clientPerfReports = (String)project.Properties["clientPerfReports"];
                string serverPerfReports = (String)project.Properties["serverPerfReports"];
                string performanceReports = isClient ? clientPerfReports : serverPerfReports;

                string indexHtml = performanceReports + @"\index.html";
                FileStream fsw = new FileStream(indexHtml, FileMode.Create, FileAccess.Write);
                StreamWriter sw = new StreamWriter(fsw);

                sw.WriteLine("<html> <head> <title>Performance Metrics</title>");
                sw.WriteLine("</head>");
                sw.WriteLine("<frameset cols=\"20%,80%\">");
                sw.WriteLine("<frameset rows=\"30%,70%\">");
                sw.WriteLine("<frame src=\"packages.html\" name=\"packageListFrame\">");
                sw.WriteLine("<frame src=\"allClasses.html\" name=\"classListFrame\">");
                sw.WriteLine("</frameset>");
                sw.WriteLine("<frame src=\"summary.html\" name=\"classFrame\">");
                sw.WriteLine("</html>");
                sw.Close();
                fsw.Close();
              }

            
              public static void ScriptMain(Project project)
              {

                string type = (String)project.Properties["perfReportType"];
                Boolean isClient = type.Equals("Client") ? true : false;
          	    string clientPerfReports = (String)project.Properties["clientPerfReports"];
                string serverPerfReports = (String)project.Properties["serverPerfReports"];
                string performanceReports = isClient ? clientPerfReports : serverPerfReports;

                string styleSheet = performanceReports + @"\stylesheet.css";
                FileStream fsw = new FileStream(styleSheet, FileMode.Create, FileAccess.Write);
                StreamWriter sw = new StreamWriter(fsw);

                sw.WriteLine("body {");
                sw.WriteLine("font:normal 68% verdana,arial,helvetica;");
                sw.WriteLine("color:#000000; }");
                sw.WriteLine("table tr td, table tr th {");
                sw.WriteLine("font-size: 68%; }");
                sw.WriteLine("table.details tr th{");
                sw.WriteLine("font-weight: bold;");
                sw.WriteLine("text-align:left;");
                sw.WriteLine("background:#a6caf0; }");
                sw.WriteLine("table.details tr td{");
                sw.WriteLine("background:#eeeee0; }");
                sw.WriteLine("h1 {");
                sw.WriteLine("margin: 0px 0px 5px; font: 165% verdana,arial,helvetica }");
                sw.WriteLine("h2 {");
                sw.WriteLine("margin-top: 1em; margin-bottom: 0.5em; font: bold 125% verdana,arial,helvetica }");
                sw.WriteLine("h3 {");
                sw.WriteLine("margin-bottom: 0.5em; font: bold 115% verdana,arial,helvetica }");
                sw.WriteLine("h4 {");
                sw.WriteLine("margin-bottom: 0.5em; font: bold 100% verdana,arial,helvetica }");

                sw.Close();
                fsw.Close();

              }
